#!/bin/bash
# ArtOnly Blog Expand Script - Batch B (15 posts)
# Generated: 2026-06-11
set -e
echo "=== ArtOnly Blog Expand Batch B: 2026-06-11 ==="

python3 << 'PYEOF'
import json, os, base64
POSTS_DIR = os.path.expanduser("~/artonly.io/posts")

def update(slug, body_b64):
    path = f"{POSTS_DIR}/{slug}.json"
    if not os.path.exists(path):
        print(f"SKIP: {slug}")
        return
    with open(path) as f:
        d = json.load(f)
    d["body"] = base64.b64decode(body_b64).decode("utf-8")
    with open(path, "w") as f:
        json.dump(d, f, indent=2, ensure_ascii=False)
    print(f"Updated: {slug}")

update("underground-club-culture-london-2022", "")
update("urtrax-immersive-music-for-the-mind", "")
update("vagabon-again-album", "")
update("vegyn-the-producer-who-stayed", "")
update("venice-biennale-2024", "")
update("verraco-basic-maneuvers", "")
update("vinyl-surpasses-cds-2024", "")
update("virgil-abloh-legacy-2022", "")
update("waxahatchee", "")
update("wesley-joseph-forever-ends-someday", "")
update("wet-leg", "")
update("wishgxd-toronto-cinematic-rb", "")
update("witch-prophet-words-are-spells", "")
update("women-reshaping-rap-2026", "")
update("wong-kar-wai-criterion-2023", "")

print("All posts updated.")
PYEOF

echo "=== Expand Batch B complete ==="
